 355→/**
 356→ * Query the total spend for a workspace (sum of trace costs).
 357→ */
 358→export async function getWorkspaceSpend(
 359→  surreal: Surreal,
 360→  workspaceId: string,
 361→): Promise<number> {
 362→  const workspaceRecord = new RecordId("workspace", workspaceId);
 363→
 364→  const results = await surreal.query(
 365→    `SELECT cost_usd FROM trace WHERE workspace = $ws;`,
 366→    { ws: workspaceRecord },
 367→  );
 368→
 369→  const rows = (results[0] ?? []) as Array<{ cost_usd: number }>;
 370→  return rows.reduce((sum, row) => sum + (row.cost_usd ?? 0), 0);
 371→}
