 696→/**
 697→ * Seed an agent session directly for testing scenarios
 698→ * that need pre-existing session data.
 699→ */
 700→export async function seedAgentSession(
 701→  surreal: Surreal,
 702→  sessionId: string,
 703→  options: {
 704→    workspaceId: string;
 705→    agent?: string;
 706→    source?: string;
 707→    externalSessionId?: string;
 708→    startedAt?: Date;
 709→    lastActivityAt?: Date;
 710→    endedAt?: Date;
 711→  },
 712→): Promise<string> {
 713→  const sessionRecord = new RecordId("agent_session", sessionId);
 714→  const workspaceRecord = new RecordId("workspace", options.workspaceId);
 715→
 716→  const content: Record<string, unknown> = {
 717→    agent: options.agent ?? "coding-agent",
 718→    workspace: workspaceRecord,
 719→    started_at: options.startedAt ?? new Date(),
 720→    last_event_at: options.lastActivityAt ?? new Date(),
 721→    created_at: new Date(),
 722→  };
 723→
 724→  if (options.externalSessionId) {
 725→    content.external_session_id = options.externalSessionId;
 726→  }
 727→  if (options.endedAt) {
 728→    content.ended_at = options.endedAt;
 729→  }
 730→  if (options.source) {
