1104→  ).catch(() => undefined); // Ignore if already exists
1105→
1106→  const input: Record<string, unknown> = {};
1107→  if (options.conversationId) {
1108→    input.conversation = new RecordId("conversation", options.conversationId);
1109→  }
1110→
1111→  const output: Record<string, unknown> = {
1112→    content: [{ type: "text", text: options.responseText }],
1113→    stop_reason: options.stopReason ?? "end_turn",
1114→  };
1115→
1116→  await surreal.query(`CREATE $trace CONTENT $content;`, {
1117→    trace: traceRecord,
1118→    content: {
1119→      type: "llm_call",
1120→      model: options.model,
1121→      actor: actorRecord,
1122→      workspace: workspaceRecord,
1123→      input_tokens: options.inputTokens ?? 100,
1124→      output_tokens: options.outputTokens ?? 50,
1125→      cache_read_tokens: 0,
1126→      cache_creation_tokens: 0,
1127→      cost_usd: options.costUsd ?? 0.001,
1128→      latency_ms: 500,
1129→      stop_reason: options.stopReason ?? "end_turn",
1130→      input,
1131→      output,
1132→      created_at: new Date(),
1133→    },
1134→  });
1135→
1136→  // Create workspace edge
1137→  await surreal.query(
1138→    `RELATE $trace->scoped_to->$workspace SET created_at = time::now();`,
1139→    { trace: traceRecord, workspace: workspaceRecord },
1140→  );
1141→
1142→  // Link to session: set session field on trace AND create invoked edge
1143→  if (options.sessionId) {
1144→    const sessionRecord = new RecordId("agent_session", options.sessionId);
1145→    await surreal.query(
1146→      `UPDATE $trace SET session = $sess;`,
1147→      { trace: traceRecord, sess: sessionRecord },
1148→    );
1149→    await surreal.query(
1150→      `RELATE $sess->invoked->$trace SET created_at = time::now();`,
1151→      { trace: traceRecord, sess: sessionRecord },
1152→    );
1153→  }
1154→
1155→  return traceId;
1156→}
